 91	 final Title successTitle = Title.title(
 92	 Component.text("ʀᴛᴘ ᴢᴏɴᴇ", NamedTextColor.RED),
 93	 Component.text("Fight players and steal their loot", NamedTextColor.WHITE),
 94	 Title.Times.times(Duration.ofSeconds(1), Duration.ofSeconds(3), Duration.ofSeconds(1))
 95	 );
 96	
 97	 for (UUID uuid : players) {
 98	 Player player = Bukkit.getPlayer(uuid);
 99	 if (player != null) {
 100	 player.teleportAsync(location).thenAccept(success -> {
 101	 if (success) {
 102	 player.showTitle(successTitle);
 103	 }
 104	 });
 105	 }
 106	 }
 107	 }
