 1	package com.omdmrotat.rtpportal;
 2	
 3	import net.kyori.adventure.text.Component;
 4	import net.kyori.adventure.text.format.NamedTextColor;
 5	import net.kyori.adventure.title.Title;
 6	import org.bukkit.Bukkit;
 7	import org.bukkit.entity.Player;
 8	
 9	import java.time.Duration;
 10	import java.util.UUID;
 11	
 12	
 13	public class PortalRTPTask implements Runnable {
 14	
 15	 private final RTPPortal plugin;
 16	
 17	 public PortalRTPTask(RTPPortal plugin) {
 18	 this.plugin = plugin;
 19	 }
 20	
 21	 @Override
 22	 public void run() {
 23	 if (plugin.getPlayersInPortal().isEmpty()) {
 24	 plugin.getTeleportTimer().set(30); // todo make it configurable
 25	 return;
 26	 }
 27	
 28	 int currentTime = plugin.getTeleportTimer().get();
 29	
 30	
 31	 for (UUID playerUUID : plugin.getPlayersInPortal()) {
 32	 Player player = Bukkit.getPlayer(playerUUID);
 33	 if (player != null) {
 34	 sendCountdownTitle(player, currentTime);
 35	 }
 36	 }
 37	
 38	 if (currentTime == 0) {
 39	 plugin.getTeleportManager().findAndTeleportPlayers(plugin.getPlayersInPortal());
 40	 }
 41	
 42	 if (plugin.getTeleportTimer().decrementAndGet() < 0) {
 43	 plugin.getTeleportTimer().set(30);
 44	 }
 45	 }
 46	
 47	 private void sendCountdownTitle(Player player, int time) {
 48	 if (time <= 0) return;
 49	 /* donutsmp rtpzone title replica */
 50	 final Component mainTitle = Component.text("ʀᴛᴘ ᴢᴏɴᴇ", NamedTextColor.RED);
 51	 final Component subtitle = Component.text("Teleporting in " + time, NamedTextColor.WHITE);
 52	 final Title.Times times = Title.Times.times(Duration.ZERO, Duration.ofSeconds(2), Duration.ofSeconds(1));
 53	 final Title title = Title.title(mainTitle, subtitle, times);
 54	 player.showTitle(title);
 55	 }
