 1	package com.omdmrotat.rtpportal;
 2	
 3	import org.bukkit.Material;
 4	import org.bukkit.configuration.file.FileConfiguration;
 5	
 6	import java.util.List;
 7	import java.util.Set;
 8	import java.util.stream.Collectors;
 9	
 10	public class ConfigManager {
 11	
 12	 private final RTPPortal plugin;
 13	 private FileConfiguration config;
 14	
 15	 private String regionName;
 16	 private String worldName;
 17	 private int minX, maxX, minZ, maxZ;
 18	 private Set<Material> safeBlockTypes;
 19	
 20	 public ConfigManager(RTPPortal plugin) {
 21	 this.plugin = plugin;
 22	 loadConfig();
 23	 }
 24	
 25	 public void loadConfig() {
 26	 plugin.saveDefaultConfig();
 27	 plugin.reloadConfig();
 28	 config = plugin.getConfig();
 29	
 30	 regionName = config.getString("region-name", "portal_rtp");
 31	 worldName = config.getString("teleport-bounds.world", "world");
 32	 minX = config.getInt("teleport-bounds.x.min", -1000);
 33	 maxX = config.getInt("teleport-bounds.x.max", 1000);
 34	 minZ = config.getInt("teleport-bounds.z.min", -1000);
 35	 maxZ = config.getInt("teleport-bounds.z.max", 1000);
 36	
 37	 List<String> materialNames = config.getStringList("safe-block-types");
 38	 safeBlockTypes = materialNames.stream()
 39	 .map(Material::matchMaterial)
 40	 .filter(java.util.Objects::nonNull)
 41	 .collect(Collectors.toSet());
 42	
 43	 if (safeBlockTypes.isEmpty()) {
 44	 plugin.getLogger().warning("No valid safe block types found in config.yml!");
 45	 }
 46	 }
 47	
 48	 // Getters for all the configuration values
 49	 public String getRegionName() { return regionName; }
 50	 public String getWorldName() { return worldName; }
 51	 public int getMinX() { return minX; }
 52	 public int getMaxX() { return maxX; }
 53	 public int getMinZ() { return minZ; }
 54	 public int getMaxZ() { return maxZ; }
 55	 public Set<Material> getSafeBlockTypes() { return safeBlockTypes; }
 56	}...
