 30	 @EventHandler
 31	 public void onPlayerMove(PlayerMoveEvent event) {
 32	 // Optimization: Don't run logic if the player hasn't moved to a new block
 33	 if (event.getFrom().getBlockX() == event.getTo().getBlockX() &&
 34	 event.getFrom().getBlockZ() == event.getTo().getBlockZ() &&
 35	 event.getFrom().getBlockY() == event.getTo().getBlockY()) {
 36	 return;
 37	 }
 38	
 39	 Player player = event.getPlayer();
 40	 RegionContainer container = WorldGuard.getInstance().getPlatform().getRegionContainer();
 41	 RegionManager regions = container.get(BukkitAdapter.adapt(player.getWorld()));
 42	
 43	 // Cannot check regions if the region manager is null
 44	 if (regions == null) return;
 45	
 46	 // Get the regions at the old and new locations
 47	 ApplicableRegionSet fromSet = regions.getApplicableRegions(BukkitAdapter.adapt(event.getFrom()).toVector().toBlockPoint());
 48	 ApplicableRegionSet toSet = regions.getApplicableRegions(BukkitAdapter.adapt(event.getTo()).toVector().toBlockPoint());
 49	
 50	 boolean wasInRegion = fromSet.getRegions().stream().anyMatch(r -> r.getId().equalsIgnoreCase(regionId));
 51	 boolean isInRegion = toSet.getRegions().stream().anyMatch(r -> r.getId().equalsIgnoreCase(regionId));
 52	
 53	 // Player entered the region
 54	 if (isInRegion && !wasInRegion) {
 55	 if (plugin.getPlayersInPortal().add(player.getUniqueId())) {
 56	 player.playSound(player.getLocation(), Sound.BLOCK_BEACON_POWER_SELECT, 1.0f, 1.0f);
 57	 sendInitialTitle(player);
 58	 }
 59	 }
 60	 // Player left the region
 61	 else if (wasInRegion && !isInRegion) {
 62	 if (plugin.getPlayersInPortal().remove(player.getUniqueId())) {
 63	 player.playSound(player.getLocation(), Sound.BLOCK_BEACON_POWER_SELECT, 1.0f, 1.0f);
 64	 }
 65	 }
 66	 }
