 73	 int currentTime = plugin.getTeleportTimer().get();
 74	 if (currentTime <= 0) return;
 75	
 76	 final Component mainTitle = Component.text("ʀᴛᴘ ᴢᴏɴᴇ", NamedTextColor.RED);
 77	 final Component subtitle = Component.text("Teleporting in " + currentTime, NamedTextColor.WHITE);
 78	
 79	 final Title.Times times = Title.Times.times(Duration.ZERO, Duration.ofSeconds(2), Duration.ofSeconds(1));
 80	 final Title title = Title.title(mainTitle, subtitle, times);
 81	
 82	 player.showTitle(title);
 83	 }
