 65	 public int getMinZ() { return minZ; }
 66	 public int getMaxZ() { return maxZ; }
 67	 public Set<Material> getSafeBlockTypes() { return safeBlockTypes; }
 68	 public int getTeleportTimer() { return teleportTimer; }
 69	
 70	 // CombatLogX integration getters
 71	 public boolean isPreventCombatTeleport() { return preventCombatTeleport; }
 72	 public String getCombatMessage() { return combatMessage; }
 73	 public boolean isRemoveCombatPlayers() { return removeCombatPlayers; }
