ld.getMaxHeight() - 1; y > world.getMinHeight(); y--) {\n Block groundBlock = world.getBlockAt(x, y, z);\n if (safeBlocks.contains(groundBlock.getType())) {\n Block feetBlock = world.getBlockAt(x, y + 1, z);\n Block headBlock = world.getBlockAt(x, y + 2, z);\n\n // Check if the player space is clear (not solid blocks)\n if (!feetBlock.getType().isSolid() && !headBlock.getType().isSolid()) {\n Location potentialLocation = new Location(world, x + 0.5, y + 1, z + 0.5);\n \n // Check for water if water detection is enabled\n if (plugin.getConfigManager().isWaterDetectionEnabled()) {\n if (!isLocationSafeFromWater(world, x, y + 1, z)) {\n continue; // Skip this location, too much water\n }\n }\n \n return potentialLocation;\n }\n }\n }\n return null;\n }", "old_str_start_line_number_1": 68, "old_str_end_line_number_1": 87}","mcp_server_name":"","mcp_tool_name":""}},{"id":2,"type":0,"content":"Now let me enhance the TeleportManager to include comprehensive water detection:
