lated blocks\n if (material == Material.SPONGE ||\n material == Material.WET_SPONGE ||\n material == Material.PRISMARINE ||\n material == Material.PRISMARINE_BRICKS ||\n material == Material.DARK_PRISMARINE ||\n material == Material.SEA_LANTERN) {\n return true;\n }\n \n return false;\n }", "old_str_start_line_number_1": 149, "old_str_end_line_number_1": 163}","mcp_server_name":"","mcp_tool_name":""}},{"id":2,"type":0,"content":"Let me also add some additional water-related materials that I might have missed and improve the detection:
