 1	package com.omdmrotat.rtpportal;
 2	
 3	import com.sk89q.worldguard.WorldGuard;
 4	import io.papermc.paper.threadedregions.scheduler.ScheduledTask;
 5	import com.sk89q.worldguard.protection.regions.RegionContainer;
 6	import io.papermc.paper.threadedregions.scheduler.AsyncScheduler;
 7	import org.bukkit.Bukkit;
 8	import org.bukkit.plugin.java.JavaPlugin;
 9	import java.util.concurrent.TimeUnit;
 10	import java.util.Collections;
 11	import java.util.HashSet;
 12	import java.util.Set;
 13	import java.util.UUID;
 14	import java.util.concurrent.atomic.AtomicInteger;
 15	
 16	public class RTPPortal extends JavaPlugin {
 17	 private ConfigManager configManager;
 18	 private static RTPPortal instance;
 19	 private TeleportManager teleportManager;
 20	 private static boolean isFolia = false;
 21	
 22	 private final Set<UUID> playersInPortal = Collections.synchronizedSet(new HashSet<>());
 23	 private final AtomicInteger teleportTimer = new AtomicInteger(30);
 24	
 25	 private RegionContainer regionContainer;
 26	 private ScheduledTask portalTask;
 27	
 28	 @Override
 29	 public void onEnable() {
 30	 instance = this;
 31	 configManager = new ConfigManager(this);
 32	 teleportManager = new TeleportManager(this);
 33	 try {
 34	 Class.forName("io.papermc.paper.threadedregions.RegionizedServer");
 35	 isFolia = true;
 36	 getLogger().info("Folia detected. Running with Folia support.");
 37	 } catch (ClassNotFoundException e) {
 38	 isFolia = false;
 39	 getLogger().info("Folia not detected. Running in standard Bukkit/Paper mode.");
 40	 }
 41	
 42	
 43	 if (getServer().getPluginManager().getPlugin("WorldGuard") == null) {
 44	 getLogger().severe("WorldGuard not found! This plugin is required.");
 45	 getServer().getPluginManager().disablePlugin(this);
 46	 return;
 47	 }
 48	 regionContainer = WorldGuard.getInstance().getPlatform().getRegionContainer();
 49	
 50	
 51	 getServer().getPluginManager().registerEvents(new PlayerConnectionListener(this), this);
 52	 getServer().getPluginManager().registerEvents(new WorldGuardRegionListener(this), this);
 53	
 54	
 55	 if (getServer().getPluginManager().getPlugin("PlaceholderAPI") != null) {
 56	 new RTPPlaceholder(this).register();
 57	 getLogger().info("Successfully hooked into PlaceholderAPI.");
 58	 }
 59	
 60	
 61	 AsyncScheduler scheduler = getServer().getAsyncScheduler();
 62	
 63	
 64	 PortalRTPTask portalRunnable = new PortalRTPTask(this);
 65	
 66	
 67	 portalTask = scheduler.runAtFixedRate(this, task -> portalRunnable.run(), 0, 1, TimeUnit.SECONDS);
 68	
 69	 getLogger().info("RTPPortal has been enabled successfully.");
 70	 }
 71	
 72	 @Override
 73	 public void onDisable() {
 74	 if (portalTask != null) {
 75	 portalTask.cancel();
 76	 }
 77	 playersInPortal.clear();
 78	 getLogger().info("RTPPortal has been disabled.");
 79	 }
 80	
 81	 public static RTPPortal getInstance() {
 82	 return instance;
 83	 }
 84	
 85	 public static boolean isFolia() {
 86	 return isFolia;
 87	 }
 88	
 89	 public Set<UUID> getPlayersInPortal() {
 90	 return playersInPortal;
 91	 }
 92	
 93	 public AtomicInteger getTeleportTimer() {
 94	 return teleportTimer;
 95	 }
 96	
 97	 public RegionContainer getRegionContainer() {
 98	 return regionContainer;
 99	 }
 100	 public ConfigManager getConfigManager() {
 101	 return configManager;
 102	 }
 103	 public TeleportManager getTeleportManager() {
 104	 return teleportManager;
 105	 }
 106	}...
