 1	package com.omdmrotat.rtpportal;
 2	
 3	import com.sk89q.worldguard.WorldGuard;
 4	import io.papermc.paper.threadedregions.scheduler.ScheduledTask;
 5	import com.sk89q.worldguard.protection.regions.RegionContainer;
 6	import io.papermc.paper.threadedregions.scheduler.AsyncScheduler;
 7	import org.bukkit.Bukkit;
 8	import org.bukkit.plugin.java.JavaPlugin;
 9	import java.util.concurrent.TimeUnit;
 10	import java.util.Collections;
 11	import java.util.HashSet;
 12	import java.util.Set;
 13	import java.util.UUID;
 14	import java.util.concurrent.atomic.AtomicInteger;
 15	
 16	public class RTPPortal extends JavaPlugin {
 17	 private ConfigManager configManager;
 18	 private static RTPPortal instance;
 19	 private TeleportManager teleportManager;
 20	 private CombatLogXIntegration combatLogXIntegration;
 21	 private static boolean isFolia = false;
 22	
 23	 private final Set<UUID> playersInPortal = Collections.synchronizedSet(new HashSet<>());
 24	 private final AtomicInteger teleportTimer = new AtomicInteger();
 25	
 26	 private RegionContainer regionContainer;
 27	 private ScheduledTask portalTask;
 28	
 29	 @Override
 30	 public void onEnable() {
 31	 instance = this;
 32	 configManager = new ConfigManager(this);
 33	 teleportManager = new TeleportManager(this);
 34	 combatLogXIntegration = new CombatLogXIntegration(this);
 35	
 36	 // Initialize timer with configured value
 37	 teleportTimer.set(configManager.getTeleportTimer());
 38	 try {
 39	 Class.forName("io.papermc.paper.threadedregions.RegionizedServer");
 40	 isFolia = true;
 41	 getLogger().info("Folia detected. Running with Folia support.");
 42	 } catch (ClassNotFoundException e) {
 43	 isFolia = false;
 44	 getLogger().info("Folia not detected. Running in standard Bukkit/Paper mode.");
 45	 }
 46	
 47	
 48	 if (getServer().getPluginManager().getPlugin("WorldGuard") == null) {
 49	 getLogger().severe("WorldGuard not found! This plugin is required.");
 50	 getServer().getPluginManager().disablePlugin(this);
 51	 return;
 52	 }
 53	 regionContainer = WorldGuard.getInstance().getPlatform().getRegionContainer();
 54	
 55	
 56	 getServer().getPluginManager().registerEvents(new PlayerConnectionListener(this), this);
 57	 getServer().getPluginManager().registerEvents(new WorldGuardRegionListener(this), this);
 58	
 59	
 60	 if (getServer().getPluginManager().getPlugin("PlaceholderAPI") != null) {
 61	 new RTPPlaceholder(this).register();
 62	 getLogger().info("Successfully hooked into PlaceholderAPI.");
 63	 }
 64	
 65	
 66	 AsyncScheduler scheduler = getServer().getAsyncScheduler();
 67	
 68	
 69	 PortalRTPTask portalRunnable = new PortalRTPTask(this);
 70	
 71	
 72	 portalTask = scheduler.runAtFixedRate(this, task -> portalRunnable.run(), 0, 1, TimeUnit.SECONDS);
 73	
 74	 getLogger().info("RTPPortal has been enabled successfully.");
 75	 }
 76	
 77	 @Override
 78	 public void onDisable() {
 79	 if (portalTask != null) {
 80	 portalTask.cancel();
 81	 }
 82	 playersInPortal.clear();
 83	 getLogger().info("RTPPortal has been disabled.");
 84	 }
 85	
 86	 public static RTPPortal getInstance() {
 87	 return instance;
 88	 }
 89	
 90	 public static boolean isFolia() {
 91	 return isFolia;
 92	 }
 93	
 94	 public Set<UUID> getPlayersInPortal() {
 95	 return playersInPortal;
 96	 }
 97	
 98	 public AtomicInteger getTeleportTimer() {
 99	 return teleportTimer;
 100	 }
 101	
 102	 public RegionContainer getRegionContainer() {
 103	 return regionContainer;
 104	 }
