 1	package com.omdmrotat.rtpportal;
 2	
 3	import org.bukkit.Material;
 4	import org.bukkit.configuration.file.FileConfiguration;
 5	
 6	import java.util.List;
 7	import java.util.Set;
 8	import java.util.stream.Collectors;
 9	
 10	public class ConfigManager {
 11	
 12	 private final RTPPortal plugin;
 13	 private FileConfiguration config;
 14	
 15	 private String regionName;
 16	 private String worldName;
 17	 private int minX, maxX, minZ, maxZ;
 18	 private Set<Material> safeBlockTypes;
 19	 private int teleportTimer;
 20	
 21	 // CombatLogX integration settings
 22	 private boolean preventCombatTeleport;
 23	 private String combatMessage;
 24	
 25	 public ConfigManager(RTPPortal plugin) {
 26	 this.plugin = plugin;
 27	 loadConfig();
 28	 }
 29	
 30	 public void loadConfig() {
 31	 plugin.saveDefaultConfig();
 32	 plugin.reloadConfig();
 33	 config = plugin.getConfig();
 34	
 35	 regionName = config.getString("region-name", "portal_rtp");
 36	 worldName = config.getString("teleport-bounds.world", "world");
 37	 minX = config.getInt("teleport-bounds.x.min", -1000);
 38	 maxX = config.getInt("teleport-bounds.x.max", 1000);
 39	 minZ = config.getInt("teleport-bounds.z.min", -1000);
 40	 maxZ = config.getInt("teleport-bounds.z.max", 1000);
 41	 teleportTimer = config.getInt("teleport-timer", 30);
 42	
 43	 List<String> materialNames = config.getStringList("safe-block-types");
 44	 safeBlockTypes = materialNames.stream()
 45	 .map(Material::matchMaterial)
 46	 .filter(java.util.Objects::nonNull)
 47	 .collect(Collectors.toSet());
 48	
 49	 if (safeBlockTypes.isEmpty()) {
 50	 plugin.getLogger().warning("No valid safe block types found in config.yml!");
 51	 }
 52	
 53	 // Load CombatLogX integration settings
 54	 preventCombatTeleport = config.getBoolean("combatlogx.prevent-combat-teleport", true);
 55	 combatMessage = config.getString("combatlogx.combat-message", "&cYou cannot be teleported while in combat!");
 56	 }
 57	
 58	 // Getters for all the configuration values
 59	 public String getRegionName() { return regionName; }
 60	 public String getWorldName() { return worldName; }
 61	 public int getMinX() { return minX; }
 62	 public int getMaxX() { return maxX; }
 63	 public int getMinZ() { return minZ; }
 64	 public int getMaxZ() { return maxZ; }
 65	 public Set<Material> getSafeBlockTypes() { return safeBlockTypes; }
 66	 public int getTeleportTimer() { return teleportTimer; }
 67	
 68	 // CombatLogX integration getters
 69	 public boolean isPreventCombatTeleport() { return preventCombatTeleport; }
 70	 public String getCombatMessage() { return combatMessage; }
 71	}...
