 1	package com.omdmrotat.rtpportal;
 2	
 3	import io.papermc.paper.threadedregions.scheduler.RegionScheduler;
 4	import net.kyori.adventure.text.Component;
 5	import net.kyori.adventure.text.format.NamedTextColor;
 6	import net.kyori.adventure.title.Title;
 7	import org.bukkit.Bukkit;
 8	import org.bukkit.Location;
 9	import org.bukkit.Material;
 10	import org.bukkit.World;
 11	import org.bukkit.block.Block;
 12	import org.bukkit.entity.Player;
 13	
 14	import java.time.Duration;
 15	import java.util.HashSet;
 16	import java.util.Set;
 17	import java.util.UUID;
 18	import java.util.concurrent.ThreadLocalRandom;
 19	
 20	public class TeleportManager {
 21	
 22	 private final RTPPortal plugin;
 23	 private static final int MAX_ATTEMPTS = 25;
 24	
 25	 public TeleportManager(RTPPortal plugin) {
 26	 this.plugin = plugin;
 27	 }
 28	
 29	 public void findAndTeleportPlayers(Set<UUID> playerUUIDs) {
 30	 Set<UUID> playersToTeleport = new HashSet<>(playerUUIDs);
 31	 playerUUIDs.clear();
 32	 tryFindingLocation(playersToTeleport, 0);
 33	 }
 34	
 35	 /**
 36	 * This method now uses a more robust downward scan to find a safe location.
 37	 */
 38	 private void tryFindingLocation(Set<UUID> playersToTeleport, int attempt) {
 39	 if (attempt >= MAX_ATTEMPTS) {
 40	 plugin.getLogger().severe("Could not find a safe teleport location after " + MAX_ATTEMPTS + " attempts! Check your config's bounds and safe-block-types.");
 41	 return;
 42	 }
 43	
 44	 ConfigManager cfg = plugin.getConfigManager();
 45	 World world = Bukkit.getWorld(cfg.getWorldName());
 46	 if (world == null) return;
 47	
 48	 int x = ThreadLocalRandom.current().nextInt(cfg.getMinX(), cfg.getMaxX() + 1);
 49	 int z = ThreadLocalRandom.current().nextInt(cfg.getMinZ(), cfg.getMaxZ() + 1);
 50	
 51	 RegionScheduler regionScheduler = Bukkit.getRegionScheduler();
 52	 Location regionKeyLocation = new Location(world, x, 0, z);
 53	
 54	 regionScheduler.execute(plugin, regionKeyLocation, () -> {
 55	 // Asynchronously get the chunk before scanning
 56	 world.getChunkAtAsync(world.getChunkAt(regionKeyLocation).getX(), world.getChunkAt(regionKeyLocation).getZ()).thenAccept(chunk -> {
 57	 Location safeSpot = findSafeSpotInChunk(world, x, z);
 58	
 59	 if (safeSpot != null) {
 60	 teleportPlayersToLocation(playersToTeleport, safeSpot);
 61	 } else {
 62	 tryFindingLocation(playersToTeleport, attempt + 1);
 63	 }
 64	 });
 65	 });
 66	 }
 67	
 68	 /**
 69	 * Scans downwards from the max build height to find a valid landing spot.
 70	 * @return A safe Location to teleport to, or null if none is found.
 71	 */
 72	 private Location findSafeSpotInChunk(World world, int x, int z) {
 73	 Set<Material> safeBlocks = plugin.getConfigManager().getSafeBlockTypes();
 74	
 75	 for (int y = world.getMaxHeight() - 1; y > world.getMinHeight(); y--) {
 76	 Block groundBlock = world.getBlockAt(x, y, z);
 77	 if (safeBlocks.contains(groundBlock.getType())) {
 78	 Block feetBlock = world.getBlockAt(x, y + 1, z);
 79	 Block headBlock = world.getBlockAt(x, y + 2, z);
 80	
 81	 if (!feetBlock.getType().isSolid() && !headBlock.getType().isSolid()) {
 82	 return new Location(world, x + 0.5, y + 1, z + 0.5);
 83	 }
 84	 }
 85	 }
 86	 return null;
 87	 }
 88	
 89	 private void teleportPlayersToLocation(Set<UUID> players, Location location) {
 90	 /* donutsmp rtpzone title replica */
 91	 final Title successTitle = Title.title(
 92	 Component.text("ʀᴛᴘ ᴢᴏɴᴇ", NamedTextColor.RED),
 93	 Component.text("Fight players and steal their loot", NamedTextColor.WHITE),
 94	 Title.Times.times(Duration.ofSeconds(1), Duration.ofSeconds(3), Duration.ofSeconds(1))
 95	 );
 96	
 97	 for (UUID uuid : players) {
 98	 Player player = Bukkit.getPlayer(uuid);
 99	 if (player != null) {
 100	 // Double-check combat status before teleporting (safety measure)
