 26	 public ConfigManager(RTPPortal plugin) {
 27	 this.plugin = plugin;
 28	 loadConfig();
 29	 }
 30	
 31	 public void loadConfig() {
 32	 plugin.saveDefaultConfig();
 33	 plugin.reloadConfig();
 34	 config = plugin.getConfig();
 35	
 36	 regionName = config.getString("region-name", "portal_rtp");
 37	 worldName = config.getString("teleport-bounds.world", "world");
 38	 minX = config.getInt("teleport-bounds.x.min", -1000);
 39	 maxX = config.getInt("teleport-bounds.x.max", 1000);
 40	 minZ = config.getInt("teleport-bounds.z.min", -1000);
 41	 maxZ = config.getInt("teleport-bounds.z.max", 1000);
 42	 teleportTimer = config.getInt("teleport-timer", 30);
 43	
 44	 List<String> materialNames = config.getStringList("safe-block-types");
 45	 safeBlockTypes = materialNames.stream()
 46	 .map(Material::matchMaterial)
 47	 .filter(java.util.Objects::nonNull)
 48	 .collect(Collectors.toSet());
 49	
 50	 if (safeBlockTypes.isEmpty()) {
 51	 plugin.getLogger().warning("No valid safe block types found in config.yml!");
 52	 }
 53	
 54	 // Load CombatLogX integration settings
 55	 preventCombatTeleport = config.getBoolean("combatlogx.prevent-combat-teleport", true);
 56	 combatMessage = config.getString("combatlogx.combat-message", "&cYou cannot be teleported while in combat!");
 57	 removeCombatPlayers = config.getBoolean("combatlogx.remove-combat-players", false);
 58	 }
 59	
 60	 // Getters for all the configuration values
 61	 public String getRegionName() { return regionName; }
 62	 public String getWorldName() { return worldName; }
 63	 public int getMinX() { return minX; }
 64	 public int getMaxX() { return maxX; }
 65	 public int getMinZ() { return minZ; }
 66	 public int getMaxZ() { return maxZ; }
 67	 public Set<Material> getSafeBlockTypes() { return safeBlockTypes; }
 68	 public int getTeleportTimer() { return teleportTimer; }
 69	
 70	 // CombatLogX integration getters
 71	 public boolean isPreventCombatTeleport() { return preventCombatTeleport; }
 72	 public String getCombatMessage() { return combatMessage; }
 73	 public boolean isRemoveCombatPlayers() { return removeCombatPlayers; }
 74	}...
