 75	 * Clean up players who are offline or no longer in the portal region
 76	 */
 77	 private void cleanupPlayersInPortal() {
 78	 Set<UUID> playersToRemove = new HashSet<>();
 79	
 80	 for (UUID playerUUID : plugin.getPlayersInPortal()) {
 81	 Player player = Bukkit.getPlayer(playerUUID);
 82	 if (player == null || !isPlayerInPortalRegion(player)) {
 83	 playersToRemove.add(playerUUID);
 84	 }
 85	 }
 86	
 87	 // Remove players who are no longer valid
 88	 for (UUID playerUUID : playersToRemove) {
 89	 plugin.getPlayersInPortal().remove(playerUUID);
 90	 Player player = Bukkit.getPlayer(playerUUID);
 91	 if (player != null) {
 92	 plugin.getLogger().info("Removed " + player.getName() + " from portal - no longer in region.");
 93	 }
 94	 }
 95	 }
 96	
 97	 /**
 98	 * Check if a player is currently in the portal region
 99	 */
 100	 private boolean isPlayerInPortalRegion(Player player) {
 101	 try {
 102	 RegionManager regions = WorldGuard.getInstance().getPlatform()
 103	 .getRegionContainer().get(BukkitAdapter.adapt(player.getWorld()));
 104	
 105	 if (regions == null) return false;
 106	
 107	 ApplicableRegionSet regionSet = regions.getApplicableRegions(
 108	 BukkitAdapter.adapt(player.getLocation()).toVector().toBlockPoint());
 109	
 110	 String regionId = plugin.getConfigManager().getRegionName();
 111	 return regionSet.getRegions().stream()
 112	 .anyMatch(r -> r.getId().equalsIgnoreCase(regionId));
 113	 } catch (Exception e) {
 114	 plugin.getLogger().warning("Error checking region for player " + player.getName() + ": " + e.getMessage());
 115	 return false;
 116	 }
 117	 }
