 61	 new RTPPlaceholder(this).register();
 62	 getLogger().info("Successfully hooked into PlaceholderAPI.");
 63	 }
 64	
 65	
 66	 AsyncScheduler scheduler = getServer().getAsyncScheduler();
 67	
 68	
 69	 PortalRTPTask portalRunnable = new PortalRTPTask(this);
 70	
 71	
 72	 portalTask = scheduler.runAtFixedRate(this, task -> portalRunnable.run(), 0, 1, TimeUnit.SECONDS);
 73	
 74	 getLogger().info("RTPPortal has been enabled successfully.");
 75	 }
