 35	 /**
 36	 * This method now uses a more robust downward scan to find a safe location.
 37	 */
 38	 private void tryFindingLocation(Set<UUID> playersToTeleport, int attempt) {
 39	 if (attempt >= MAX_ATTEMPTS) {
 40	 plugin.getLogger().severe("Could not find a safe teleport location after " + MAX_ATTEMPTS + " attempts! Check your config's bounds and safe-block-types.");
 41	 return;
 42	 }
 43	
 44	 ConfigManager cfg = plugin.getConfigManager();
 45	 World world = Bukkit.getWorld(cfg.getWorldName());
 46	 if (world == null) return;
 47	
 48	 int x = ThreadLocalRandom.current().nextInt(cfg.getMinX(), cfg.getMaxX() + 1);
 49	 int z = ThreadLocalRandom.current().nextInt(cfg.getMinZ(), cfg.getMaxZ() + 1);
 50	
 51	 RegionScheduler regionScheduler = Bukkit.getRegionScheduler();
 52	 Location regionKeyLocation = new Location(world, x, 0, z);
 53	
 54	 regionScheduler.execute(plugin, regionKeyLocation, () -> {
 55	 // Asynchronously get the chunk before scanning
 56	 world.getChunkAtAsync(world.getChunkAt(regionKeyLocation).getX(), world.getChunkAt(regionKeyLocation).getZ()).thenAccept(chunk -> {
 57	 Location safeSpot = findSafeSpotInChunk(world, x, z);
 58	
 59	 if (safeSpot != null) {
 60	 teleportPlayersToLocation(playersToTeleport, safeSpot);
 61	 } else {
 62	 tryFindingLocation(playersToTeleport, attempt + 1);
 63	 }
 64	 });
 65	 });
 66	 }
 67	
 68	 /**
 69	 * Scans downwards from the max build height to find a valid landing spot.
 70	 * Now includes water detection to prevent teleporting into water-filled areas.
 71	 * @return A safe Location to teleport to, or null if none is found.
 72	 */
 73	 private Location findSafeSpotInChunk(World world, int x, int z) {
 74	 Set<Material> safeBlocks = plugin.getConfigManager().getSafeBlockTypes();
 75	
 76	 for (int y = world.getMaxHeight() - 1; y > world.getMinHeight(); y--) {
 77	 Block groundBlock = world.getBlockAt(x, y, z);
 78	 if (safeBlocks.contains(groundBlock.getType())) {
 79	 Block feetBlock = world.getBlockAt(x, y + 1, z);
 80	 Block headBlock = world.getBlockAt(x, y + 2, z);
 81	
 82	 // Check if the player space is clear (not solid blocks)
 83	 if (!feetBlock.getType().isSolid() && !headBlock.getType().isSolid()) {
 84	 Location potentialLocation = new Location(world, x + 0.5, y + 1, z + 0.5);
 85	
 86	 // Check for water if water detection is enabled
 87	 if (plugin.getConfigManager().isWaterDetectionEnabled()) {
 88	 if (!isLocationSafeFromWater(world, x, y + 1, z)) {
 89	 continue; // Skip this location, too much water
 90	 }
 91	
 92	 // Additional check: avoid ocean biomes if configured
 93	 if (plugin.getConfigManager().isAvoidOceanBiomes() && isOceanBiome(world, x, z)) {
 94	 plugin.getLogger().info("Rejected location at " + x + "," + (y + 1) + "," + z +
 95	 " - located in ocean biome");
 96	 continue;
 97	 }
 98	 }
 99	
 100	 return potentialLocation;
 101	 }
 102	 }
 103	 }
 104	 return null;
 105	 }
