 113	 * @return true if the location is safe from water, false otherwise
 114	 */
 115	 private boolean isLocationSafeFromWater(World world, int x, int y, int z) {
 116	 ConfigManager config = plugin.getConfigManager();
 117	 int radius = config.getWaterCheckRadius();
 118	 double maxWaterPercentage = config.getMaxWaterPercentage();
 119	
 120	 // Check horizontal area around the teleport location
 121	 int totalBlocks = 0;
 122	 int waterBlocks = 0;
...
 136	
 137	 // Calculate liquid percentage in the area (water + lava)
 138	 double liquidPercentage = (double) waterBlocks / totalBlocks;
 139	 if (liquidPercentage > maxWaterPercentage) {
 140	 plugin.getLogger().info("Rejected location at " + x + "," + y + "," + z +
 141	 " - too much liquid (water/lava): " + String.format("%.1f%%", liquidPercentage * 100) +
 142	 " (max allowed: " + String.format("%.1f%%", maxWaterPercentage * 100) + ")");
 143	 return false;
 144	 }
 145	
 146	 // Check for water above if enabled (prevents underwater caves)
 147	 if (config.isCheckWaterAbove()) {
 148	 int checkHeight = config.getCheckAboveHeight();
 149	 for (int dy = 1; dy <= checkHeight; dy++) {
 150	 Block blockAbove = world.getBlockAt(x, y + dy, z);
 151	 if (isWaterBlock(blockAbove.getType()) || blockAbove.getType() == Material.LAVA) {
 152	 plugin.getLogger().info("Rejected location at " + x + "," + y + "," + z +
 153	 " - liquid (water/lava) detected " + dy + " blocks above");
 154	 return false;
 155	 }
 156	 }
 157	 }
 158	
 159	 return true;
 160	 }
