 162	 /**
 163	 * Checks if a material is a water block (including waterlogged blocks and ocean-related blocks).
 164	 * @param material The material to check
 165	 * @return true if the material is water-related
 166	 */
 167	 private boolean isWaterBlock(Material material) {
 168	 // Direct water blocks
 169	 if (material == Material.WATER) {
 170	 return true;
 171	 }
 172	
 173	 // Ocean plants and decorations
 174	 if (material == Material.KELP ||
 175	 material == Material.KELP_PLANT ||
 176	 material == Material.SEAGRASS ||
 177	 material == Material.TALL_SEAGRASS ||
 178	 material == Material.SEA_PICKLE) {
 179	 return true;
 180	 }
 181	
 182	 // Coral blocks and related
 183	 String materialName = material.name();
 184	 if (materialName.contains("CORAL") ||
 185	 materialName.contains("TUBE_CORAL") ||
 186	 materialName.contains("BRAIN_CORAL") ||
 187	 materialName.contains("BUBBLE_CORAL") ||
 188	 materialName.contains("FIRE_CORAL") ||
 189	 materialName.contains("HORN_CORAL")) {
 190	 return true;
 191	 }
 192	
 193	 // Other ocean-related blocks
 194	 if (material == Material.SPONGE ||
 195	 material == Material.WET_SPONGE ||
 196	 material == Material.PRISMARINE ||
 197	 material == Material.PRISMARINE_BRICKS ||
 198	 material == Material.DARK_PRISMARINE ||
 199	 material == Material.SEA_LANTERN) {
 200	 return true;
 201	 }
 202	
 203	 return false;
 204	 }
