 211	 * @return true if the location is in an ocean biome
 212	 */
 213	 private boolean isOceanBiome(World world, int x, int z) {
 214	 try {
 215	 String biomeName = world.getBiome(x, 64, z).name();
 216	 return biomeName.contains("OCEAN") ||
 217	 biomeName.contains("DEEP_OCEAN") ||
 218	 biomeName.equals("WARM_OCEAN") ||
 219	 biomeName.equals("LUKEWARM_OCEAN") ||
 220	 biomeName.equals("COLD_OCEAN") ||
 221	 biomeName.equals("FROZEN_OCEAN");
 222	 } catch (Exception e) {
 223	 // If we can't determine the biome, assume it's safe
 224	 return false;
 225	 }
 226	 }
