 233	 Title.Times.times(Duration.ofSeconds(1), Duration.ofSeconds(3), Duration.ofSeconds(1))
 234	 );
 235	
 236	 for (UUID uuid : players) {
 237	 Player player = Bukkit.getPlayer(uuid);
 238	 if (player != null) {
 239	 // Double-check combat status before teleporting (safety measure)
 240	 if (plugin.getConfigManager().isPreventCombatTeleport() &&
 241	 plugin.getCombatLogXIntegration().isInCombat(player)) {
 242	 plugin.getLogger().info("Skipping teleportation for " + player.getName() + " - still in combat.");
 243	 continue;
 244	 }
 245	
 246	 player.teleportAsync(location).thenAccept(success -> {
 247	 if (success) {
 248	 player.showTitle(successTitle);
 249	 }
 250	 });
 251	 }
 252	 }
 253	 }
