 10	public class ConfigManager {
 11	
 12	 private final RTPPortal plugin;
 13	 private FileConfiguration config;
 14	
 15	 private String regionName;
 16	 private String worldName;
 17	 private int minX, maxX, minZ, maxZ;
 18	 private Set<Material> safeBlockTypes;
 19	 private int teleportTimer;
 20	
 21	 // Water detection settings
 22	 private boolean waterDetectionEnabled;
 23	 private int waterCheckRadius;
 24	 private double maxWaterPercentage;
 25	 private boolean checkWaterAbove;
 26	 private int checkAboveHeight;
 27	 private boolean avoidOceanBiomes;
 28	
 29	 // CombatLogX integration settings
 30	 private boolean preventCombatTeleport;
 31	 private String combatMessage;
 32	 private boolean removeCombatPlayers;
 33	
 34	 public ConfigManager(RTPPortal plugin) {
 35	 this.plugin = plugin;
 36	 loadConfig();
 37	 }
 38	
 39	 public void loadConfig() {
 40	 plugin.saveDefaultConfig();
 41	 plugin.reloadConfig();
 42	 config = plugin.getConfig();
 43	
 44	 regionName = config.getString("region-name", "portal_rtp");
 45	 worldName = config.getString("teleport-bounds.world", "world");
 46	 minX = config.getInt("teleport-bounds.x.min", -1000);
 47	 maxX = config.getInt("teleport-bounds.x.max", 1000);
 48	 minZ = config.getInt("teleport-bounds.z.min", -1000);
 49	 maxZ = config.getInt("teleport-bounds.z.max", 1000);
 50	 teleportTimer = config.getInt("teleport-timer", 30);
 51	
 52	 List<String> materialNames = config.getStringList("safe-block-types");
 53	 safeBlockTypes = materialNames.stream()
 54	 .map(Material::matchMaterial)
 55	 .filter(java.util.Objects::nonNull)
 56	 .collect(Collectors.toSet());
 57	
 58	 if (safeBlockTypes.isEmpty()) {
 59	 plugin.getLogger().warning("No valid safe block types found in config.yml!");
 60	 }
 61	
 62	 // Load water detection settings
 63	 waterDetectionEnabled = config.getBoolean("water-detection.enabled", true);
 64	 waterCheckRadius = config.getInt("water-detection.check-radius", 3);
 65	 maxWaterPercentage = config.getDouble("water-detection.max-water-percentage", 0.3);
 66	 checkWaterAbove = config.getBoolean("water-detection.check-above", true);
 67	 checkAboveHeight = config.getInt("water-detection.check-above-height", 5);
 68	 avoidOceanBiomes = config.getBoolean("water-detection.avoid-ocean-biomes", true);
 69	
 70	 // Load CombatLogX integration settings
 71	 preventCombatTeleport = config.getBoolean("combatlogx.prevent-combat-teleport", true);
 72	 combatMessage = config.getString("combatlogx.combat-message", "&cYou cannot be teleported while in combat!");
 73	 removeCombatPlayers = config.getBoolean("combatlogx.remove-combat-players", false);
 74	 }
